UPDATE challenge 
SET is_deleted = 1 
WHERE id = #{id}

UPDATE challenge
SET state = 'IN_PROGRESS',
	real_start_date = #{date}
WHERE id = #{id}

UPDATE challenge
SET state = 'SUCCESS',
	real_end_date = #{date}
WHERE id = #{id}

UPDATE challenge
SET state = 'GIVE_UP',
	real_end_date = #{date}
WHERE id = #{id}
